def trans(term, clue, category, wrongs, prompt):
    return {m:{'prompt':prompt,'correct_answer':term,'wrong_answers':wrongs} for m in ['rapid_classification','signal_vs_noise','stroop_test','odd_one_out','memory_cascade','sequence_reverse','pattern_continuation','spatial_recall']}
subroot=APP/'data/observation_banks/creative_arts/worlds/drawing/subcategories'; runtime=APP/'data/content/base_bundle/creative_arts/drawing'
subroot.mkdir(parents=True,exist_ok=True)
if runtime.exists(): shutil.rmtree(runtime)
runtime.mkdir(parents=True,exist_ok=True)
wm_path=APP/'data/observation_banks/creative_arts/worlds/drawing/world_manifest.json'; wm=json.load(open(wm_path))
for sc in wm['subcategories']: sc.update({'implemented_observations':100,'status':'complete','scenario_preferences':prefs})
wm['status']='complete'; json.dump(wm,open(wm_path,'w'),indent=2)
compiled=[]
for subname,pool in subcats.items():
    subid=sid(subname); obs=[]
    for i in range(100):
        term,clue,cat=pool[i%len(pool)]; wrongs=distract(term,pool); label,tier=diff(i); oid=f'creative_arts_drawing_{subid}_{i+1:04d}'; variant=i//len(pool)
        prompt=[f'Which drawing term matches: {clue}?',f'In {subname}, what means {clue}?',f'Name the {cat} described as: {clue}.',f'Which {subname.lower()} concept is {clue}?'][variant%4]
        knowledge={'domain':'drawing','subcategory':subid,'term':term,'concept':term,'definition_clue':clue,'recognized_answer':term,'distractor_family':wrongs,'difficulty_tier':tier,'keywords':[subid,sid(term),sid(cat)],'category':cat}
        transformations=trans(term,clue,cat,wrongs,prompt)
        obs.append({'observation_id':oid,'universe':'creative_arts','world':'drawing','subcategory':subid,'difficulty':{'label':label,'tier':tier},'observation_type':'Rapid Recognition','base_fact':f'{term}: {clue}.','prompt':prompt,'correct_answer':term,'distractors':wrongs,'localization':{'prompt_key':oid+'_prompt','answer_key':oid+'_answer'},'knowledge':knowledge,'mechanic_transformations':transformations,'metadata':{'tags':knowledge['keywords'],'scenario_compatibility':prefs,'deterministic_seed_key':oid,'quality':{'recognition':5,'visual_presentation':5,'fast_comprehension':5,'replayability':5,'educational_value':5,'mobile_readability':5},'source_basis':'Drawing education reference set based on studio drawing fundamentals.','knowledge':knowledge,'mechanic_transformations':transformations}})
        for mech,rule in transformations.items(): compiled.append({'id':f'{oid}_{mech}','observation_id':oid,'universe':'creative_arts','world':'drawing','subcategory':subid,'type':mech,'rules':{'prompt':prompt,'legacy_prompt':prompt,'correct_answer':rule['correct_answer'],'wrong_answers':rule['wrong_answers']},'presentation':{'title':f'Drawing — {subname}','difficulty_tier':tier,'subcategory':subid,'observation_type':mech},'knowledge':knowledge,'metadata':{'source_observation_id':oid,'knowledge':knowledge,'mechanic_transformations':transformations,'built_by':'drawing_state_machine_compiler'}})
    bank={'schema_version':1,'observation_bank_version':'creative_arts.v1.drawing','universe':'creative_arts','world':'drawing','subcategory':subid,'display_name':subname,'constraint_vector':{'core_concept_space':f'Drawing concepts bounded to {subname}.','allowed_elements':['widely taught drawing vocabulary','tools','methods','visual principles','figure and construction concepts'],'forbidden_elements':['software-only image editing','temporary social media styles','obscure artist gossip','opinion-only prompts'],'domain_anchors':['studio drawing fundamentals','art-school drawing exercises','publicly taught illustration vocabulary'],'mechanic_suitability_map':prefs},'scenario_preferences':prefs,'observations':obs}
    json.dump(bank,open(subroot/f'{subid}.json','w'),indent=2,ensure_ascii=False)
json.dump(compiled,open(runtime/'drawing_observation_bank_compiled.json','w'),indent=2,ensure_ascii=False)
print('drawing observations',sum(len(json.load(open(p))['observations']) for p in subroot.glob('*.json')),'compiled',len(compiled))
